try:
    from msvcrt import get_osfhandle
except ImportError:
    def get_osfhandle(_):
        """Stub replacement for msvcrt.get_osfhandle when not on Windows.

        This function mirrors the signature of msvcrt.get_osfhandle but always
        raises OSError to indicate that the functionality is not available on
        non-Windows platforms.
        """
        raise OSError("This isn't windows!")


from . import win32

# from wincon.h
class WinColor(object):
    BLACK   = 0
    BLUE    = 1
    GREEN   = 2
    CYAN    = 3
    RED     = 4
    MAGENTA = 5
    YELLOW  = 6
    GREY    = 7

# from wincon.h
class WinStyle(object):
    NORMAL              = 0x00 # dim text, dim background
    BRIGHT              = 0x08 # bright text, dim background
    BRIGHT_BACKGROUND   = 0x80 # dim text, bright background

class WinTerm(object):

    def __init__(self):
        """Initialize a WinTerm instance.

        The constructor captures the current console attributes so that they
        can be restored later. It also initializes internal tracking for
        foreground, background and style attributes as well as any emulated
        "light" bits that are represented using style flags on Windows.
        """
        self._default = win32.GetConsoleScreenBufferInfo(win32.STDOUT).wAttributes
        self.set_attrs(self._default)
        self._default_fore = self._fore
        self._default_back = self._back
        self._default_style = self._style
        # In order to emulate LIGHT_EX in windows, we borrow the BRIGHT style.
        # So that LIGHT_EX colors and BRIGHT style do not clobber each other,
        # we track them separately, since LIGHT_EX is overwritten by Fore/Back
        # and BRIGHT is overwritten by Style codes.
        self._light = 0

    def get_attrs(self):
        """Return the current combined attribute value.

        The returned integer encodes foreground, background and style bits in
        the same way that the Windows console API expects.
        """
        return self._fore + self._back * 16 + (self._style | self._light)

    def set_attrs(self, value):
        """Set the internal foreground, background and style from a value.

        The value is interpreted as a combined console attribute integer, and
        the internal fields are extracted from it.
        """
        self._fore = value & 7
        self._back = (value >> 4) & 7
        self._style = value & (WinStyle.BRIGHT | WinStyle.BRIGHT_BACKGROUND)

    def reset_all(self, on_stderr=None):
        """Reset console attributes to the saved defaults.

        If on_stderr is provided it will be used to select stderr rather than
        stdout when applying the attributes.
        """
        self.set_attrs(self._default)
        self.set_console(attrs=self._default)
        self._light = 0

    def fore(self, fore=None, light=False, on_stderr=False):
        """Set the foreground color.

        If fore is None, the default saved foreground is used. The light flag
        controls whether the foreground uses the emulated LIGHT_EX behaviour.
        """
        if fore is None:
            fore = self._default_fore
        self._fore = fore
        # Emulate LIGHT_EX with BRIGHT Style
        if light:
            self._light |= WinStyle.BRIGHT
        else:
            self._light &= ~WinStyle.BRIGHT
        self.set_console(on_stderr=on_stderr)

    def back(self, back=None, light=False, on_stderr=False):
        """Set the background color.

        If back is None, the default saved background is used. The light flag
        controls whether the background uses the emulated LIGHT_EX behaviour.
        """
        if back is None:
            back = self._default_back
        self._back = back
        # Emulate LIGHT_EX with BRIGHT_BACKGROUND Style
        if light:
            self._light |= WinStyle.BRIGHT_BACKGROUND
        else:
            self._light &= ~WinStyle.BRIGHT_BACKGROUND
        self.set_console(on_stderr=on_stderr)

    def style(self, style=None, on_stderr=False):
        """Set the style bits (such as BRIGHT) for text and/or background.

        If style is None, the default saved style is used.
        """
        if style is None:
            style = self._default_style
        self._style = style
        self.set_console(on_stderr=on_stderr)

    def set_console(self, attrs=None, on_stderr=False):
        """Apply attributes to the console.

        If attrs is None the current attributes from get_attrs() are used.
        on_stderr controls whether to apply to stderr instead of stdout.
        """
        if attrs is None:
            attrs = self.get_attrs()
        handle = win32.STDOUT
        if on_stderr:
            handle = win32.STDERR
        win32.SetConsoleTextAttribute(handle, attrs)

    def get_position(self, handle):
        """Return the current cursor position for the given console handle.

        The returned position is adjusted to be 1-based for compatibility with
        callers that expect 1-based coordinates.
        """
        position = win32.GetConsoleScreenBufferInfo(handle).dwCursorPosition
        # Because Windows coordinates are 0-based,
        # and win32.SetConsoleCursorPosition expects 1-based.
        position.X += 1
        position.Y += 1
        return position

    def set_cursor_position(self, position=None, on_stderr=False):
        """Set the console cursor position.

        If position is None the method does nothing. on_stderr controls whether
        to operate on stderr rather than stdout.
        """
        if position is None:
            # I'm not currently tracking the position, so there is no default.
            # position = self.get_position()
            return
        handle = win32.STDOUT
        if on_stderr:
            handle = win32.STDERR
        win32.SetConsoleCursorPosition(handle, position)

    def cursor_adjust(self, x, y, on_stderr=False):
        """Move the cursor relative to its current position.

        x and y are deltas for the X and Y coordinates respectively. on_stderr
        controls whether to operate on stderr rather than stdout.
        """
        handle = win32.STDOUT
        if on_stderr:
            handle = win32.STDERR
        position = self.get_position(handle)
        adjusted_position = (position.Y + y, position.X + x)
        win32.SetConsoleCursorPosition(handle, adjusted_position, adjust=False)

    def erase_screen(self, mode=0, on_stderr=False):
        """Erase part or all of the screen.

        mode:
            0  Clear from cursor to end of screen.
            1  Clear from cursor to beginning of screen.
            2  Clear entire screen and move cursor to home position.

        on_stderr controls whether to operate on stderr rather than stdout.
        """
        handle = win32.STDOUT
        if on_stderr:
            handle = win32.STDERR
        csbi = win32.GetConsoleScreenBufferInfo(handle)
        width = csbi.dwSize.X
        height = csbi.dwSize.Y
        total = width * height
        cursor = csbi.dwCursorPosition
        # Compute start index as number of character cells before the cursor.
        cursor_index = cursor.Y * width + cursor.X

        if mode == 0:
            # From cursor to end of screen.
            start_index = cursor_index
            length = total - start_index
            start_coord = cursor
        elif mode == 1:
            # From beginning to cursor.
            start_index = 0
            length = cursor_index + 1
            start_coord = win32.COORD(0, 0)
        elif mode == 2:
            # Entire screen.
            start_index = 0
            length = total
            start_coord = win32.COORD(0, 0)
        else:
            # Unknown mode: do nothing.
            return

        # Fill with spaces and reset attributes.
        try:
            win32.FillConsoleOutputCharacter(handle, ' ', length, start_coord)
            win32.FillConsoleOutputAttribute(handle, csbi.wAttributes, length, start_coord)
            if mode == 2:
                # Move cursor to home for full clear.
                win32.SetConsoleCursorPosition(handle, win32.COORD(0, 0))
        except Exception:
            # If any operation fails, we don't want to raise the error here.
            # The goal is best-effort clearing of the screen.
            pass

    def erase_line(self, mode=0, on_stderr=False):
        """Erase part or all of the current line.

        mode:
            0  Clear from cursor to end of line.
            1  Clear from cursor to beginning of line.
            2  Clear entire line.

        on_stderr controls whether to operate on stderr rather than stdout.
        """
        handle = win32.STDOUT
        if on_stderr:
            handle = win32.STDERR
        csbi = win32.GetConsoleScreenBufferInfo(handle)
        width = csbi.dwSize.X
        cursor = csbi.dwCursorPosition
        cursor_index = cursor.X  # column index within the line

        if mode == 0:
            start_coord = cursor
            length = width - cursor_index
        elif mode == 1:
            start_coord = win32.COORD(0, cursor.Y)
            length = cursor_index + 1
        elif mode == 2:
            start_coord = win32.COORD(0, cursor.Y)
            length = width
        else:
            return

        try:
            win32.FillConsoleOutputCharacter(handle, ' ', length, start_coord)
            win32.FillConsoleOutputAttribute(handle, csbi.wAttributes, length, start_coord)
        except Exception:
            # Best-effort; swallow exceptions similar to erase_screen.
            pass

    def set_title(self, title):
        """Set the console window title to the provided string."""
        try:
            win32.SetConsoleTitle(title)
        except Exception:
            # If setting the title fails, silently ignore.
            pass


def enable_vt_processing(handle):
    """Enable Virtual Terminal Processing for the given console handle.

    This attempts to turn on the ENABLE_VIRTUAL_TERMINAL_PROCESSING bit for
    the console mode associated with the provided handle. Returns True on
    success and False on failure.
    """
    try:
        mode = win32.GetConsoleMode(handle)
    except Exception:
        return False
    ENABLE_VIRTUAL_TERMINAL_PROCESSING = 0x0004
    try:
        win32.SetConsoleMode(handle, mode | ENABLE_VIRTUAL_TERMINAL_PROCESSING)
    except Exception:
        return False
    return True